    "text_instructions": [
      {
        "id": "01eeb60f6c4911439e2954a4abd8f363",
        "content": [
          "* when asking about VaR use data_rooms.vw_risk_var_nop_main_instruments_history\r\n",
          "* when asking about VaR use filed VaR and not VaR_instrument\r\n",
          "* when asking about VaR use Report_time to order by or to filter\r\n",
          "* field scenario_date is useful when asking the date of reference for the var calculation\r\n",
          "\r\n",
          "* CVaR is not VaR.\r\n",
          "*  when asking about VaR witout define % use the default\r\n",
          "* default VaR is percentile 99.5\r\n",
          "* when the user ask anything about VaR without specifying number, it's important to highlight the following message \"Our default VaR is based on percentile 99.5%. If you want another value, please specify it\"\r\n",
          "\r\n",
          "* NOPHedged is not NOP. \r\n",
          "* NOPHedge can be defined as NOP Hedged\r\n",
          "\r\n",
          "* eff lev is effective leverage or leverage \r\n",
          "* for effective leverage long positions filter  IsBuy = true\r\n",
          "* for effective leverage short positions filter  IsBuy = false\r\n",
          "* if the user didn't specify long or short show both \r\n",
          "* when asking what is the var please add also the Report_time\r\n",
          "* when ask who are the top contributors to var, it refer to the last Report_time exist and to var_instrument and but InstrumentID present also InstrumentName\r\n",
          "* when ask oil use 'XTI%'\r\n",
          "* always present InstrumentID and InstrumentName\r\n",
          "* s&p500 or s&p means 'SPX%'\r\n"
        ]
      }
    ],
    "example_question_sqls": [
      {
        "id": "01eee05653f91f299590179a84e53c58",
        "question": [
          "when user is asking you about trend, please  divide the period to two, than calculate the average for each two period and compare them, in dollar amount and percentage"
        ],
        "sql": [
          "WITH Periods AS (\n",
          "  SELECT \n",
          "    VaR, \n",
          "    Report_time,\n",
          "    CASE \n",
          "      WHEN Report_time < date_sub(CURRENT_DATE, 45) THEN 'FirstHalf'\n",
          "      ELSE 'SecondHalf'\n",
          "    END AS Period\n",
          "  FROM main.data_rooms.vw_risk_var_nop_main_instruments_history\n",
          "  WHERE Percentile = 99.5 AND Report_time >= date_sub(CURRENT_DATE, 90)\n",
          ")\n",
          "SELECT \n",
          "  Period,\n",
          "  AVG(VaR) AS AverageVaR\n",
          "FROM Periods\n",
          "GROUP BY Period"
        ]
      }
    ]
